namespace Vc.Generators.Security;

[Generator(LanguageNames.CSharp)]
public sealed class VcSecurityGenerator : IIncrementalGenerator
{
    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        var candidates = context.SyntaxProvider
            .CreateSyntaxProvider(
                static (node, _) => node is ClassDeclarationSyntax or MethodDeclarationSyntax && ((BaseTypeDeclarationSyntax)node).AttributeLists.Count > 0,
                static (ctx, ct) => Transform(ctx, ct))
            .Where(static m => m is not null)!;

        var compilationAndModels = context.CompilationProvider.Combine(candidates.Collect());

        context.RegisterSourceOutput(compilationAndModels, static (spc, pair) =>
        {
            var (compilation, models) = pair;
            if (models.IsDefaultOrEmpty)
            {
                return;
            }

            // Group by permission group to avoid duplication
            var grouped = models
                .Where(m => !string.IsNullOrWhiteSpace(m!.GroupName))
                .Cast<SecurityModel>()
                .GroupBy(m => (m.Namespace, m.GroupName), StringComparer.OrdinalIgnoreCase);

            foreach (var group in grouped)
            {
                EmitPermissionCatalog(spc, group.Key.Namespace, group.Key.GroupName, group.SelectMany(m => m.Permissions));
                EmitAuthorizationPolicies(spc, group.Key.Namespace, group.Key.GroupName, group.SelectMany(m => m.Permissions));
                EmitSecurityGuards(spc, group.Key.Namespace, group.Key.GroupName, group.SelectMany(m => m.Permissions));
            }
        });
    }

    private static SecurityModel? Transform(GeneratorSyntaxContext context, CancellationToken ct)
    {
        ct.ThrowIfCancellationRequested();

        if (context.Node is ClassDeclarationSyntax classDecl)
        {
            var symbol = context.SemanticModel.GetDeclaredSymbol(classDecl, ct) as INamedTypeSymbol;
            if (symbol is null)
            {
                return null;
            }

            if (!symbol.HasAttribute("PermissionGroupAttribute") &&
                !symbol.HasAttribute("PermissionGroup"))
            {
                return null;
            }

            var ns = symbol.ContainingNamespace?.ToDisplayString() ?? string.Empty;
            var groupAttr = symbol.GetAttribute("PermissionGroupAttribute") ?? symbol.GetAttribute("PermissionGroup");
            var groupName = groupAttr?.ConstructorArguments.Length > 0
                ? groupAttr.Value.ConstructorArguments[0].Value as string
                : symbol.Name;

            var permissions = ImmutableArray.CreateBuilder<PermissionModel>();
            var roles = ImmutableArray.CreateBuilder<RoleRequirementModel>();

            // Methods with [Secure] inside the group
            foreach (var member in symbol.GetMembers().OfType<IMethodSymbol>())
            {
                AddSecurityFromMethod(member, groupName!, permissions, roles);
            }

            return new SecurityModel(
                Namespace: ns,
                GroupName: groupName ?? symbol.Name,
                Permissions: permissions.ToImmutable(),
                Roles: roles.ToImmutable());
        }

        if (context.Node is MethodDeclarationSyntax methodDecl)
        {
            var symbol = context.SemanticModel.GetDeclaredSymbol(methodDecl, ct) as IMethodSymbol;
            if (symbol is null)
            {
                return null;
            }

            if (!symbol.HasAttribute("SecureAttribute") &&
                !symbol.HasAttribute("Secure"))
            {
                return null;
            }

            var ns = symbol.ContainingNamespace?.ToDisplayString() ?? string.Empty;
            var groupName = symbol.ContainingType?.Name ?? "DefaultSecurity";

            var permissions = ImmutableArray.CreateBuilder<PermissionModel>();
            var roles = ImmutableArray.CreateBuilder<RoleRequirementModel>();

            AddSecurityFromMethod(symbol, groupName, permissions, roles);

            return new SecurityModel(
                Namespace: ns,
                GroupName: groupName,
                Permissions: permissions.ToImmutable(),
                Roles: roles.ToImmutable());
        }

        return null;
    }

    private static void AddSecurityFromMethod(
        IMethodSymbol method,
        string groupName,
        ImmutableArray<PermissionModel>.Builder permissions,
        ImmutableArray<RoleRequirementModel>.Builder roles)
    {
        var secureAttr = method.GetAttribute("SecureAttribute") ?? method.GetAttribute("Secure");
        if (secureAttr is null || secureAttr.Value.ConstructorArguments.Length == 0)
        {
            return;
        }

        var permissionName = secureAttr.Value.ConstructorArguments[0].Value as string;
        if (string.IsNullOrWhiteSpace(permissionName))
        {
            return;
        }

        permissions.Add(new PermissionModel(
            GroupName: groupName,
            PermissionName: permissionName!,
            MethodName: method.Name));

        foreach (var roleAttr in method.GetAttributes("RequiresRoleAttribute", "RequiresRole"))
        {
            if (roleAttr.ConstructorArguments.Length == 0)
            {
                continue;
            }

            var roleName = roleAttr.ConstructorArguments[0].Value as string;
            if (string.IsNullOrWhiteSpace(roleName))
            {
                continue;
            }

            roles.Add(new RoleRequirementModel(
                PermissionName: permissionName!,
                RoleName: roleName!));
        }
    }

    private static void EmitPermissionCatalog(
        SourceProductionContext context,
        string ns,
        string groupName,
        IEnumerable<PermissionModel> permissions)
    {
        var distinctPermissions = permissions
            .GroupBy(p => p.PermissionName, StringComparer.OrdinalIgnoreCase)
            .Select(g => g.First())
            .OrderBy(p => p.PermissionName, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (distinctPermissions.Length == 0)
        {
            return;
        }

        var className = $"{groupName}Permissions";
        var fileName = $"{className}.g.cs";

        var sb = new IndentedStringBuilder();

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();

        sb.AppendLine("namespace Vc.Generated.Security;");
        sb.AppendLine();
        sb.AppendLine($"public static class {className}");
        sb.AppendLine("{");
        sb.Indent();

        foreach (var permission in distinctPermissions)
        {
            var constName = ToIdentifier(permission.PermissionName);
            sb.AppendLine($"public const string {constName} = \"{permission.PermissionName}\";");
        }

        sb.Unindent();
        sb.AppendLine("}");

        context.AddSource(fileName, SourceText.From(sb.ToString(), System.Text.Encoding.UTF8));
    }

    private static void EmitAuthorizationPolicies(
