            return;
        }

        var className = $"{groupName}AuthorizationExtensions";
        var fileName = $"{className}.g.cs";

        var sb = new IndentedStringBuilder();

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();
        sb.AppendLine("using Microsoft.Extensions.DependencyInjection;");
        sb.AppendLine("using Microsoft.AspNetCore.Authorization;");
        sb.AppendLine();
        sb.AppendLine("namespace Vc.Generated.Security;");
        sb.AppendLine();
        sb.AppendLine($"public static class {className}");
        sb.AppendLine("{");
        sb.Indent();

        sb.AppendLine("public static IServiceCollection AddGenerated" + groupName + "Authorization(this IServiceCollection services)");
        sb.AppendLine("{");
        sb.Indent();
        sb.AppendLine("services.AddAuthorization(options =>");
        sb.AppendLine("{");
        sb.Indent();

        foreach (var permission in distinctPermissions)
        {
            var constName = ToIdentifier(permission.PermissionName);
            sb.AppendLine($"options.AddPolicy({groupName}Permissions.{constName}, p => p.RequireClaim(\"permission\", {groupName}Permissions.{constName}));");
        }

        sb.Unindent();
        sb.AppendLine("});");
        sb.AppendLine();
        sb.AppendLine("return services;");
        sb.Unindent();
