        sb.Unindent();
        sb.AppendLine("}");

        context.AddSource(fileName, SourceText.From(sb.ToString(), System.Text.Encoding.UTF8));
    }

    private static void EmitSecurityGuards(
        SourceProductionContext context,
        string ns,
        string groupName,
        IEnumerable<PermissionModel> permissions)
    {
        var distinctPermissions = permissions
            .GroupBy(p => p.PermissionName, StringComparer.OrdinalIgnoreCase)
            .Select(g => g.First())
            .OrderBy(p => p.PermissionName, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        if (distinctPermissions.Length == 0)
        {
            return;
        }

        var className = $"{groupName}SecurityGuards";
        var fileName = $"{className}.g.cs";

        var sb = new IndentedStringBuilder();

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();
        sb.AppendLine("using System.Security.Claims;");
        sb.AppendLine();
        sb.AppendLine("namespace Vc.Generated.Security;");
        sb.AppendLine();
        sb.AppendLine($"public static class {className}");
        sb.AppendLine("{");
        sb.Indent();

        foreach (var permission in distinctPermissions)
        {
            var constName = ToIdentifier(permission.PermissionName);
            var methodName = $"Guard_{constName}";

            sb.AppendLine($"public static async System.Threading.Tasks.Task<T> {methodName}<T>(");
            sb.AppendLine("    ClaimsPrincipal user,");
            sb.AppendLine("    System.Func<System.Threading.Tasks.Task<T>> action)");
            sb.AppendLine("{");
            sb.Indent();
            sb.AppendLine($"if (!user.HasClaim(\"permission\", {groupName}Permissions.{constName}))");
            sb.AppendLine("{");
