    private static string ToIdentifier(string permission)
    {
        // Orders.Read -> Orders_Read
        var chars = permission.Select(c =>
            char.IsLetterOrDigit(c) ? c : '_').ToArray();
        var id = new string(chars);

        if (SyntaxFacts.IsKeywordKind(SyntaxFacts.GetKeywordKind(id)))
        {
            id = "@" + id;
        }

        return id;
    }

    private sealed record PermissionModel(
        string GroupName,
        string PermissionName,
        string MethodName);

    private sealed record RoleRequirementModel(
        string PermissionName,
        string RoleName);

    private sealed record SecurityModel(
        string Namespace,
        string GroupName,
        ImmutableArray<PermissionModel> Permissions,
        ImmutableArray<RoleRequirementModel> Roles);
}
